        // Уникальный индекс избранного — один пользователь не может добавить одну картину дважды
        modelBuilder.Entity<Favorite>()
            .HasIndex(f => new { f.PaintingId, f.SessionId })
            .IsUnique();

        // Seed: картины
        modelBuilder.Entity<Painting>().HasData(
