            new Painting { Id = 2,  Title = "Утро в сосновом лесу",         Author = "Иван Шишкин",          Style = "Реализм",               Year = 1889, Country = "Россия",      Materials = "Масло, холст",          Size = "139 × 213 см",     ImageUrl = "/images/paintings/collection2.jpg",      Description = "Картина «Утро в сосновом лесу» — одно из самых известных произведений Ивана Шишкина. Художник мастерски изобразил утренний лес, пронизанный солнечным светом. Медведи дописаны Константином Савицким." },
            new Painting { Id = 3,  Title = "Звёздная ночь",                Author = "Винсент Ван Гог",      Style = "Постимпрессионизм",     Year = 1889, Country = "Нидерланды",  Materials = "Масло, холст",          Size = "73.7 × 92.1 см",   ImageUrl = "/images/paintings/painting3.jpg",        Description = "\"Звёздная ночь\" — одна из самых узнаваемых картин Ван Гога. Художник изобразил ночной пейзаж с динамичными вихревыми облаками и яркими звёздами." },
            new Painting { Id = 4,  Title = "Девочка с персиками",          Author = "Валентин Серов",       Style = "Реализм",               Year = 1887, Country = "Россия",      Materials = "Масло, холст",          Size = "91 × 85 см",       ImageUrl = "/images/paintings/painting4.jpg",        Description = "\"Девочка с персиками\" — знаменитая картина Серова, написанная в усадьбе Абрамцево. На полотне изображена Вера Мамонтова. Эталон русского реализма." },
            new Painting { Id = 5,  Title = "Герника",                      Author = "Пабло Пикассо",        Style = "Кубизм",                Year = 1937, Country = "Испания",     Materials = "Масло, холст",          Size = "349 × 776 см",     ImageUrl = "/images/paintings/painting5.jpg",        Description = "\"Герника\" — монументальное полотно Пикассо, созданное в ответ на бомбардировку баскского города. Символ протеста против войны и насилия." },
            new Painting { Id = 6,  Title = "Впечатление. Восходящее солнце", Author = "Клод Моне",         Style = "Импрессионизм",         Year = 1872, Country = "Франция",     Materials = "Масло, холст",          Size = "48 × 63 см",       ImageUrl = "/images/paintings/painting6.jpg",        Description = "Картина Клода Моне, давшая название всему направлению импрессионизма. Художник изобразил гавань Гавра в утреннем тумане." },
            new Painting { Id = 7,  Title = "Чёрный квадрат",               Author = "Казимир Малевич",      Style = "Супрематизм",           Year = 1915, Country = "Россия",      Materials = "Масло, холст",          Size = "79.5 × 79.5 см",   ImageUrl = "/images/paintings/painting7.jpg",        Description = "\"Чёрный квадрат\" — самая известная работа Малевича, ставшая иконой супрематизма и всего русского авангарда." },
            new Painting { Id = 8,  Title = "Крик",                         Author = "Эдвард Мунк",          Style = "Экспрессионизм",        Year = 1893, Country = "Норвегия",    Materials = "Масло, темпера, картон",Size = "91 × 73.5 см",     ImageUrl = "/images/paintings/painting8.jpg",        Description = "\"Крик\" — знаменитая картина Эдварда Мунка, выражающая экзистенциальный ужас современного человека." },
