            new Painting { Id = 10, Title = "Подсолнухи",                   Author = "Винсент Ван Гог",      Style = "Постимпрессионизм",     Year = 1888, Country = "Нидерланды",  Materials = "Масло, холст",          Size = "92 × 73 см",       ImageUrl = "/images/paintings/painting10.jpg",       Description = "\"Подсолнухи\" — серия картин Ван Гога с подсолнухами в вазе. Яркие цвета и эмоциональная насыщенность делают их узнаваемыми во всём мире." },
            new Painting { Id = 11, Title = "Авиньонские девицы",           Author = "Пабло Пикассо",        Style = "Кубизм",                Year = 1907, Country = "Испания",     Materials = "Масло, холст",          Size = "243.9 × 233.7 см", ImageUrl = "/images/paintings/painting11.jpg",       Description = "\"Авиньонские девицы\" — новаторская работа Пикассо, предтеча кубизма. Радикальный разрыв с традиционной перспективой." },
