            new Painting { Id = 14, Title = "Цветы 727-727",                Author = "Такаси Мураками",      Style = "Поп-арт",               Year = 2022, Country = "Япония",      Materials = "Акрил, холст",          Size = "100 × 100 см",     ImageUrl = "/images/paintings/murakami_flowers.jpg", Description = "\"Цветы 727-727\" — работа Такаси Мураками. Яркие улыбающиеся цветы сочетают японскую эстетику с современной поп-культурой." },
