        );

        // Seed: авторы
        modelBuilder.Entity<Author>().HasData(
            new Author { Id = 1,  Name = "Сальвадор Дали",       Country = "Испания",     Years = "1904–1989", Style = "Сюрреализм",            PhotoUrl = "/images/authors/dali_author.jpg",       Bio = "Испанский художник-сюрреалист, один из самых известных представителей этого направления. Его работы отличаются фантастическими образами и виртуозной живописной техникой." },
            new Author { Id = 2,  Name = "Иван Шишкин",          Country = "Россия",      Years = "1832–1898", Style = "Реализм",               PhotoUrl = "/images/authors/shishkin_author.jpg",   Bio = "Русский художник-пейзажист, академик. Один из крупнейших мастеров реалистической пейзажной живописи. Его картины отличаются тщательной прорисовкой деталей природы." },
            new Author { Id = 3,  Name = "Винсент Ван Гог",      Country = "Нидерланды",  Years = "1853–1890", Style = "Постимпрессионизм",     PhotoUrl = "/images/authors/vangogh_author.jpg",    Bio = "Нидерландский художник-постимпрессионист. За свою короткую жизнь создал более 2000 произведений. Его экспрессивная манера оказала огромное влияние на всё западное искусство." },
            new Author { Id = 4,  Name = "Валентин Серов",       Country = "Россия",      Years = "1865–1911", Style = "Реализм",               PhotoUrl = "/images/authors/serov_author.jpg",      Bio = "Русский живописец и график, мастер портрета. Один из крупнейших русских художников рубежа XIX–XX веков. Прославился портретами представителей российской интеллигенции." },
            new Author { Id = 5,  Name = "Пабло Пикассо",        Country = "Испания",     Years = "1881–1973", Style = "Кубизм",                PhotoUrl = "/images/authors/picasso_author.jpg",    Bio = "Испанский художник, скульптор, график. Основатель кубизма. Один из самых известных и влиятельных художников XX века. Создал более 20 000 произведений." },
            new Author { Id = 6,  Name = "Клод Моне",            Country = "Франция",     Years = "1840–1926", Style = "Импрессионизм",         PhotoUrl = "/images/authors/monet_author.jpg",      Bio = "Французский живописец, основоположник импрессионизма. Работал преимущественно на пленэре. Создал знаменитые серии «Стога сена», «Руанский собор», «Кувшинки»." },
            new Author { Id = 7,  Name = "Казимир Малевич",      Country = "Россия",      Years = "1879–1935", Style = "Супрематизм",           PhotoUrl = "/images/authors/malevich_author.jpg",   Bio = "Русский и советский художник, педагог, теоретик искусства. Основатель супрематизма — одного из наиболее ранних проявлений абстрактного искусства." },
            new Author { Id = 8,  Name = "Эдвард Мунк",          Country = "Норвегия",    Years = "1863–1944", Style = "Экспрессионизм",        PhotoUrl = "/images/authors/munch_author.jpg",      Bio = "Норвежский живописец и график, театральный художник. Один из первых представителей экспрессионизма. Его работы оказали значительное влияние на развитие этого направления." },
            new Author { Id = 9,  Name = "Леонардо да Винчи",    Country = "Италия",      Years = "1452–1519", Style = "Возрождение",           PhotoUrl = "/images/authors/davinci_author.jpg",    Bio = "Итальянский художник, учёный, изобретатель, писатель, музыкант эпохи Высокого Возрождения. Гений, совместивший в себе художника и учёного." },
            new Author { Id = 10, Name = "Илья Репин",           Country = "Россия",      Years = "1844–1930", Style = "Реализм",               PhotoUrl = "/images/authors/repin_author.jpg",      Bio = "Русский живописец, педагог. Один из крупнейших мастеров русского реализма. Создал обширную галерею портретов современников, а также жанровые и исторические картины." },
            new Author { Id = 11, Name = "Джордж Кондо",         Country = "США",         Years = "1957–н.в.", Style = "Поп-арт",               PhotoUrl = "/images/authors/condo_avatar.jpg",      Bio = "Американский художник, известный своим стилем «искусственный реализм». Сочетает классические живописные техники с гротескными, юмористическими образами." },
            new Author { Id = 12, Name = "Такаси Мураками",      Country = "Япония",      Years = "1962–н.в.", Style = "Поп-арт",               PhotoUrl = "/images/authors/murakami_avatar.jpg",   Bio = "Японский художник и предприниматель. Создатель стиля «суперфлат». Работы сочетают традиционные японские мотивы с западной поп-культурой." },
            new Author { Id = 13, Name = "Валерий Кошляков",     Country = "Россия",      Years = "1962–н.в.", Style = "Современное искусство", PhotoUrl = "/images/authors/koshlyakov_avatar.jpg", Bio = "Российский художник, представитель московского акционизма и постсоветского искусства. Работает с образами архитектурных памятников, используя нетрадиционные материалы." }
        );
